import sailpoint.object.*;
import sailpoint.api.*;
import sailpoint.tools.Util;


String fileLocation = "D:\\csv files\\IIQ Application Names.txt";
String filepath = "D:\\csv files\\IIQ ApplicationDetails.txt";
String line;
String result;
String lineToBeWritten;

private  writeLine( String filepath,  String line) throws Exception {

  try{

    if (filepath == null || line == null) {
      return;
    }
    BufferedWriter  bufferedWriter  = new BufferedWriter(new FileWriter(new File(filepath), true));
    // bufferedWriter.newLine();
    bufferedWriter.write(line);
    bufferedWriter.close();
  }
  catch(Exception e){
    log.error(" error in  writeline method "+e.toString());
  }
}


try{

  BufferedReader br=new BufferedReader(new FileReader(new File(fileLocation)));
  writeLine(filepath , "ApplicationName , Type ");
  // writeLine(filepath , "ApplicationName , Type , Connector ");
  // String header=br.readLine();
  while((line=br.readLine())!=null){

    if(!line.contains(",")){
      String appName = line;
      Application appObject = context.getObjectByName(Application.class , appName);

      if (appObject == null) {
        return;   // skip this line safely
      }

      String connector = appObject.getConnector();
      String type  = appObject.getType();

     // lineToBeWritten ="\n"+ line +" , "+ type+" , " +connector.substring(connector.indexOf('.', connector.indexOf('.') + 1) + 1)+"\n";
      lineToBeWritten = "\n"+line +" , "+ type;

      writeLine(filepath , lineToBeWritten);
      log.error(" data written in new file  "+lineToBeWritten);
    }
  }
}catch(Exception e){
  log.error(e.toString());
}




























